VALUES
  ('judicial-57f41407-moex-00753', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「僵局國會」（HungParliament）又稱「均勢國會」（BalancedParliament），是指在議會內閣制國家中，沒有 一個政黨在議會選舉中取得絕對多數的席次，導致政府難產。在議會內閣制國家中，一旦出現「僵局國會」 時，即可能採用下列何種方式作為解決的方案？', '["成立「分立政府」（dividedgovernment）", "籌組「聯合內閣」（coalitioncabinet）", "設置「影子內閣」（shadowcabinet）", "實施「左右共治」（cohabitation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00754', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '報載：「2013年6月間，酒駕新制施行後，某國小校長涉嫌酒駕肇事，由於酒測值高達0.73毫克，被依公 共危險罪移送法辦。同時，教育局也停止他的校長職務，並移交公務員懲戒委員會審議，最重可以撤職處 分。一旦確定撤職將喪失教育人員資格與退休金，且在移送公懲會後亦不得申請退休。」下列針對報載內 容的相關敘述，何者正確？', '["「移送法辦」指移送交通法庭審理以追訴其刑責", "審議懲戒之「公務員懲戒委員會」，現已改名為「懲戒法院」，隸屬於司法院", "「審議懲戒」與「退休審核」之職權屬同一機關", "「移送法辦」與「審議懲戒」皆屬行政權之運作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00755', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '「保安處分」係對受處分人將來之危險性所為拘束其身體、自由等之處置，以達教化與治療之目的，為刑 罰之補充制度。下列何者不是「保安處分」？', '["安置輔導", "保護管束", "強制工作", "強制治療"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00756', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依我國「中央法規標準法」規定，法律應經立法院通過，總統公布。下列何者非屬立法院三讀通過的法律？', '["監獄組織通則", "貪污治罪條例", "少年事件處理法", "全民健康保險醫療辦法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00757', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '男大學生小剛在人行道上以猥褻言語，不斷騷擾並跟蹤尾隨女高中生小美，小美經大聲制止無效後報警， 警方以社會秩序維護法處理。本案涉及違反該法所保障的公共秩序為何？', '["妨害安寧秩序", "妨害公務", "妨害他人身體", "妨害他人財產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00758', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國紀念日及節日之指定、慶祝活動及放假等規範，乃依據內政部發布《紀念日及節日實施辦法》，為了 提升紀念日及節日實施之穩定性及法律位階，請問：推動《紀念日及節日實施條例》之立法，可以透過何 種方式達成？', '["人民自行連署後向立法院提出法律案", "立法委員15人以上連署提出法律案", "總統向立法院提出法律案", "大法官受理人民聲請，向立法院提出法律案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00759', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '民主國家的依法行政，包含「法律優位原則」與「法律保留原則」兩大原則。下列何者並無法律保留原則 之適用？', '["衛生福利部發布新流感疫情，呼籲國人做好自主健康管理", "交通警察取締路邊違規停車，予以開單告發並且拖吊", "為彌補財政赤字，國稅局調高個人綜合所得稅之稅率", "為刺激消費，行政院發放振興經濟消費券每人3600元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00760', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某日深夜，慣竊老王潛入陳董事長的豪宅企圖行竊，被陳董的鄰居阿強發現，阿強立即報警，並上前欲抓 住老王，雙方發生扭打，警方隨後趕來將老王逮捕。依我國相關法律規定，下列敘述何者錯誤？', '["老王的行為符合現行犯的要件，因此阿強可以逮捕他", "因正值深夜，老王有權拒絕接受警方的訊問", "老王除有權請律師與聯絡家人外，還可行使緘默權", "警方應取得老王的「自白」，因自白可做為判決的唯一證據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00761', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '生產者從事生產的最大目的在於獲取「利潤」，下列有關「利潤」的敘述，何者錯誤？', '["利潤為銷貨收入減總成本的剩餘", "利潤為商品的售價乘以銷售數量", "利潤極大化的生產者決策也符合極小化成本", "利潤為企業才能所獲得的報酬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00762', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '每年旱季印尼蘇門答臘地區農民會以傳統放火燒林的火耕方式清理耕地，加上季風因素，使新加坡常籠罩 在煙霾中，空氣污染指數屢創新高。新加坡政府表示願意提供協助，也願和其他國家合作，解決霾害問題。 此類有關全球環境之議題，下列何者較無助於推動永續發展？', '["已開發國家對開發中國家的污染防制進行技術協助", "各國政府以政策要求生產者以對環境影響最小的方式生產", "消費者購買商品時主動選擇生產過程對環境友善的產品", "推動永續發展的重責大任全部交由已開發國家來承擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
